# --- surveyking upstream (追加到 00-upstreams.conf) ---
upstream surveyking {
    server surveyking.surveyking.svc.cluster.local:1991;
}

server {
    listen 80;
    server_name xsurveyking.xtool-staging.yottastudios.com;
    return 301 https://$host$request_uri;
}

server {
    listen 443 ssl;
    server_name xsurveyking.xtool-staging.yottastudios.com;

    ssl_certificate /etc/ssl/yottastudios.com/cert.pem;
    ssl_certificate_key /etc/ssl/yottastudios.com/key.pem;

    client_max_body_size 2048m;

    location / {
        proxy_pass http://surveyking;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # WebSocket support
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";

        proxy_connect_timeout 300;
        proxy_send_timeout 300;
        proxy_read_timeout 300;
    }

    # CORS headers
    add_header Access-Control-Allow-Origin *;
    add_header Access-Control-Allow-Methods "GET, POST, PUT, DELETE, OPTIONS";
    add_header Access-Control-Allow-Headers "DNT,X-Mx-ReqToken,Keep-Alive,User-Agent,X-Requested-With,If-Modified-Since,Cache-Control,Content-Type,Authorization";
}

